import React, { useState } from "react";
import "./header.css";

const Header = () => {
  /*=============== Change Backgroun Header ===============*/
  window.addEventListener("scroll", function () {
    const header = document.querySelector(".header");
    //when the scroll in higher than 560 viewport heighr, add the scroll-header class to a tag with the header tag
    if (this.scrollY >= 80) header.classList.add("scroll-header");
    else header.classList.remove("scroll-header");
  });

  /*=============== Toggle Menu ===============*/
  const [Toggle, showMenu] = useState(false);
  const [activeNav, setActiveNave] = useState("#home");

  return (
    <>
      <header className="header">
        <nav className="nav container">
          <a href="https://www.chamikagayashan.com/" className="nav__logo">
            Chamika Gayashan
          </a>

          <div className={Toggle ? "nav__menu show-menu" : "nav__menu"}>
            <ul className="nav__list grid">
              <li className="nav__item">
                <a
                  href="#home"
                  onClick={() => setActiveNave("#home")}
                  className={
                    activeNav === "#home"
                      ? "nav__link active_link"
                      : "nav__link"
                  }
                >
                  <i className="uil uil-estate nav__icon"></i> Home
                </a>
              </li>

              <li className="nav__item">
                <a
                  href="#about"
                  onClick={() => setActiveNave("#about")}
                  className={
                    activeNav === "#about"
                      ? "nav__link active_link"
                      : "nav__link"
                  }
                >
                  <i className="uil uil-user nav__icon"></i> About
                </a>
              </li>

              <li className="nav__item">
                <a
                  href="#skills"
                  onClick={() => setActiveNave("#skills")}
                  className={
                    activeNav === "#skills"
                      ? "nav__link active_link"
                      : "nav__link"
                  }
                >
                  <i className="uil uil-file-alt  nav__icon"></i> Skills
                </a>
              </li>

              <li className="nav__item">
                <a
                  href="#services"
                  onClick={() => setActiveNave("#services")}
                  className={
                    activeNav === "#services"
                      ? "nav__link active_link"
                      : "nav__link"
                  }
                >
                  <i className="uil uil-briefcase-alt nav__icon"></i> Services
                </a>
              </li>

              {/* <li className="nav__item">
              <a
                href="#portfolio"
                onClick={() => setActiveNave("#portfolio")}
                className={
                  activeNav === "#portfolio"
                    ? "nav__link active_link"
                    : "nav__link"
                }
              >
                <i className="uil uil-scenery nav__icon"></i> Portfolio
              </a>
            </li> */}

              <li className="nav__item">
                <a
                  href="#contact"
                  onClick={() => setActiveNave("#contact")}
                  className={
                    activeNav === "#contact"
                      ? "nav__link active_link"
                      : "nav__link"
                  }
                >
                  <i className="uil uil-message nav__icon"></i> Contact
                </a>
              </li>
            </ul>

            <i
              className="uil uil-times nav__close"
              onClick={() => showMenu(!Toggle)}
            ></i>
          </div>
          <div className="nav__toggle" onClick={() => showMenu(!Toggle)}>
            <i class="uil uil-apps"></i>
          </div>
        </nav>
      </header>
    </>
  );
};

export default Header;
